{"document": {"category": "csaf_security_advisory", "csaf_version": "2.0", "distribution": {"text": "Disclosure is not limited. (TLPv2: TLP:CLEAR)", "tlp": {"label": "WHITE"}}, "lang": "en", "notes": [{"category": "summary", "text": "SINEC INS before V1.0 SP2 Update 6 is affected by multiple vulnerabilities.

Siemens has released a new version for SINEC INS and recommends to update to the latest version.", "title": "Summary"}, {"category": "general", "text": "As a general security measure, Siemens strongly recommends to protect network access to devices with appropriate mechanisms. In order to operate the devices in a protected IT environment, Siemens recommends to configure the environment according to Siemens' operational guidelines for Industrial Security (Download: https://www.siemens.com/cert/operational-guidelines-industrial-security), and to follow the recommendations in the product manuals.
Additional information on Industrial Security by Siemens can be found at: https://www.siemens.com/industrialsecurity", "title": "General Recommendations"}, {"category": "general", "text": "For further inquiries on security vulnerabilities in Siemens products and solutions, please contact the Siemens ProductCERT: https://www.siemens.com/cert/advisories", "title": "Additional Resources"}, {"category": "legal_disclaimer", "text": "The use of Siemens Security Advisories is subject to the terms and conditions listed on: https://www.siemens.com/productcert/terms-of-use.", "title": "Terms of Use"}], "publisher": {"category": "vendor", "contact_details": "productcert@siemens.com", "name": "Siemens ProductCERT", "namespace": "https://www.siemens.com"}, "references": [{"category": "self", "summary": "SSA-860189: Multiple Vulnerabilities in SINEC INS Before V1.0 SP2 Update 6 - HTML Version", "url": "https://cert-portal.siemens.com/productcert/html/ssa-860189.html"}, {"category": "self", "summary": "SSA-860189: Multiple Vulnerabilities in SINEC INS Before V1.0 SP2 Update 6 - CSAF Version", "url": "https://cert-portal.siemens.com/productcert/csaf/ssa-860189.json"}], "title": "SSA-860189: Multiple Vulnerabilities in SINEC INS Before V1.0 SP2 Update 6", "tracking": {"current_release_date": "2026-06-09T00:00:00.000Z", "generator": {"engine": {"name": "Siemens ProductCERT CSAF Generator", "version": "1"}}, "id": "SSA-860189", "initial_release_date": "2026-06-09T00:00:00.000Z", "revision_history": [{"date": "2026-06-09T00:00:00.000Z", "legacy_version": "1.0", "number": "1", "summary": "Publication Date"}], "status": "interim", "version": "1"}}, "product_tree": {"branches": [{"branches": [{"branches": [{"category": "product_version_range", "name": "vers:intdot/<1.0.2.6", "product": {"name": "SINEC INS", "product_id": "1"}}], "category": "product_name", "name": "SINEC INS"}], "category": "vendor", "name": "Siemens"}]}, "vulnerabilities": [{"cve": "CVE-2026-46746", "cwe": {"id": "CWE-78", "name": "Improper Neutralization of Special Elements used in an OS Command ('OS Command Injection')"}, "notes": [{"category": "summary", "text": "The application does not properly sanitize user input in the /api/sftp/uploadFiles endpoint, allowing the injection of shell command payloads via crafted directory names. These payloads are stored and executed when directory listings are retrieved. This could allow an authenticated remote attacker to execute arbitrary commands on the underlying operating system with the privileges of the affected service user (sinecins).", "title": "Summary"}], "product_status": {"known_affected": ["1"]}, "remediations": [{"category": "vendor_fix", "details": "Update to V1.0 SP2 Update 6 or later version", "product_ids": ["1"], "url": "https://support.industry.siemens.com/cs/ww/en/view/110002283/"}], "scores": [{"cvss_v3": {"baseScore": 8.8, "baseSeverity": "HIGH", "vectorString": "CVSS:3.1/AV:N/AC:L/PR:L/UI:N/S:U/C:H/I:H/A:H", "version": "3.1"}, "products": ["1"]}], "title": "CVE-2026-46746"}, {"cve": "CVE-2026-46747", "cwe": {"id": "CWE-26", "name": "Path Traversal: '/dir/../filename'"}, "notes": [{"category": "summary", "text": "The affected application does not properly sanitize path input in the `GET /api/sftp/uploadFiles` endpoint used for directory listing. This allows path traversal through crafted input, enabling access to unintended file system locations.", "title": "Summary"}], "product_status": {"known_affected": ["1"]}, "remediations": [{"category": "vendor_fix", "details": "Update to V1.0 SP2 Update 6 or later version", "product_ids": ["1"], "url": "https://support.industry.siemens.com/cs/ww/en/view/110002283/"}], "scores": [{"cvss_v3": {"baseScore": 4.3, "baseSeverity": "MEDIUM", "vectorString": "CVSS:3.1/AV:N/AC:L/PR:L/UI:N/S:U/C:L/I:N/A:N", "version": "3.1"}, "products": ["1"]}], "title": "CVE-2026-46747"}, {"cve": "CVE-2026-46748", "cwe": {"id": "CWE-250", "name": "Execution with Unnecessary Privileges"}, "notes": [{"category": "summary", "text": "The affected system includes a binary that is configured with the cap_dac_override capability. This capability allows the process to bypass file system permission checks, resulting in unrestricted file system access. This could allow a local attacker to escalate privileges leading to arbitrary file modification and gaining root privileges on the system.", "title": "Summary"}], "product_status": {"known_affected": ["1"]}, "remediations": [{"category": "vendor_fix", "details": "Update to V1.0 SP2 Update 6 or later version", "product_ids": ["1"], "url": "https://support.industry.siemens.com/cs/ww/en/view/110002283/"}], "scores": [{"cvss_v3": {"baseScore": 8.8, "baseSeverity": "HIGH", "vectorString": "CVSS:3.1/AV:N/AC:L/PR:L/UI:N/S:U/C:H/I:H/A:H", "version": "3.1"}, "products": ["1"]}], "title": "CVE-2026-46748"}, {"cve": "CVE-2026-46749", "cwe": {"id": "CWE-760", "name": "Use of a One-Way Hash with a Predictable Salt"}, "notes": [{"category": "summary", "text": "The affected application uses a password hashing implementation with a static, hardcoded salt shared across all users and installations, and is configured with an insufficient number of iterations. This could allow an attacker to efficiently recover user passwords using brute-force or precomputed attacks, potentially resulting in unauthorized access.", "title": "Summary"}], "product_status": {"known_affected": ["1"]}, "remediations": [{"category": "vendor_fix", "details": "Update to V1.0 SP2 Update 6 or later version", "product_ids": ["1"], "url": "https://support.industry.siemens.com/cs/ww/en/view/110002283/"}], "scores": [{"cvss_v3": {"baseScore": 7.5, "baseSeverity": "HIGH", "vectorString": "CVSS:3.1/AV:L/AC:H/PR:H/UI:N/S:C/C:H/I:H/A:H", "version": "3.1"}, "products": ["1"]}], "title": "CVE-2026-46749"}]}
